B.P_=new A.aO("dsl_accepts_everything_nfa","Accept Everything (NFA)",'Build a two-state NFA that uses a free ~-jump to accept every string. Hint: an ~-transition (no label) is a "free jump" to another state.',"      n0 = A\n      n1 = B\n      n0 = (734.0, 447.3)\n      n1 = (1022.0, 468.7)\n      n1 is accepted\n      n0 to n1\n      n1 to n1 = .\n      . loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,B.bC,B.ae,B.kw,0.4,"nfa",!1,B.H,!1,null,B.M,"",!1)
