B.Op=new A.aO("dfa_to_regex_even_as","DFA \u2192 Regex: Even a's","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} with an even number of a's.",u.m,B.E,null,B.ae,B.op,0.8,"regex",!1,B.H,!1,null,B.cH,"b*(ab*ab*)*",!1)
