B.ON=new A.aO("dfa_to_regex_starts_ab","DFA \u2192 Regex: Starts with ab",'A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} that start with "ab".',"      n0 = q0\n      n1 = q1\n      n2 = q2\n      n3 = dead\n      n0 = (240.0, 360.0)\n      n1 = (560.0, 360.0)\n      n2 = (880.0, 360.0)\n      n3 = (560.0, 600.0)\n      n2 is accepted\n      n0 to n1 = a\n      n0 to n3 = b\n      n1 to n2 = b\n      n1 to n3 = a\n      n2 to n2 = a,b\n      n3 to n3 = a,b\n      l4(a,b) loop angle = -1.5708\n      l5(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,null,B.ae,B.oq,0.2,"regex",!1,B.H,!1,null,B.cH,"ab(a+b)*",!1)
B.P6=new A.aO("dfa_to_regex_no_consec_b","DFA \u2192 Regex: No Consecutive b's","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts all strings over {a, b} containing no two consecutive b's.","      n0 = q0\n      n1 = q1\n      n2 = dead\n      n0 = (400.0, 340.0)\n      n1 = (780.0, 340.0)\n      n2 = (580.0, 580.0)\n      n0 is accepted\n      n1 is accepted\n      n0 to n1 = b\n      n0 to n0 = a\n      n1 to n0 = a\n      n1 to n2 = b\n      n2 to n2 = a,b\n      l0(a) loop angle = -1.5708\n      l4(a,b) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,null,B.ae,B.oq,0.5,"regex",!1,B.H,!1,null,B.cH,"a*(ba+)*b?",!1)
B.P8=new A.aO("dfa_to_regex_binary_mod2","DFA \u2192 Regex: Even 0s","A read-only DFA is shown on the canvas. Type a regular expression in the input box whose language is exactly what this DFA accepts.\n\nThis DFA accepts binary strings over {0, 1} with an even number of 0s.","      n0 = even\n      n1 = odd\n      n0 = (504.7, 310.0)\n      n1 = (1030.0, 314.0)\n      n0 is accepted\n      n0 to n1 = 0\n      n1 to n0 = 0\n      n0 to n0 = 1\n      n1 to n1 = 1\n      l0(0) curve = -74.1\n      l1(0) curve = -72.7\n      l2(1) loop angle = -1.5708\n      l3(1) loop angle = -1.5708\n      to n0\n      to n0 angle = -1.0000, 0.0000\n    ",B.E,null,B.dl,B.oq,0.8,"regex",!1,B.H,!1,null,B.cH,"1*(01*01*)*",!1)
